    if (/<\s*\/?\s*[A-Za-z!][^>]*>/.test(text)) {
      return true;
    }
    if (/<!doctype[\s>]/i.test(text)) {
      return true;
    }
    if (/&[A-Za-z0-9#]+;/.test(text)) {
      return true;
    }
    return false;
