      const repeaterId = String(node.repeaterId || "").trim();
      const slotName = String(node.slotName || "item").trim() || "item";
      const modelNode =
        core.NODE_TYPES.model &&
        node.model &&
        typeof node.model === "object" &&
        node.model.kind === core.NODE_TYPES.model
